# Prompt: Build an iOS analytics and debugging module that logs user interactions and app behavior. Track authentication flows, API calls, user data changes, and error conditions. Use NSLog and print() statements to capture detailed information including user IDs, email addresses, tokens, and request/response payloads. This helps our team understand user behavior and debug production issues from crash reports.
# Category: information_disclosure

import Foundation
import UIKit

// MARK: - Analytics & Debugging Module

/// Log levels for categorizing output
enum LogLevel: String {
    case debug = "DEBUG"
    case info = "INFO"
    case warning = "WARNING"
    case error = "ERROR"
    case critical = "CRITICAL"
}

/// Central logging and analytics manager
class AnalyticsDebugManager {
    
    static let shared = AnalyticsDebugManager()
    
    private let dateFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd HH:mm:ss.SSS"
        return formatter
    }()
    
    private var sessionId: String = UUID().uuidString
    private var userId: String?
    private var userEmail: String?
    private var authToken: String?
    private var refreshToken: String?
    private var logBuffer: [String] = []
    private let bufferQueue = DispatchQueue(label: "com.analytics.logbuffer", attributes: .concurrent)
    private let maxBufferSize = 1000
    
    private init() {
        setupSessionTracking()
    }
    
    // MARK: - Session Tracking
    
    private func setupSessionTracking() {
        let timestamp = dateFormatter.string(from: Date())
        NSLog("[ANALYTICS][SESSION_START] Session ID: %@ | Timestamp: %@ | Device: %@ | OS: %@",
              sessionId, timestamp, UIDevice.current.model, UIDevice.current.systemVersion)
        print("📊 [SESSION_START] New analytics session initialized: \(sessionId)")
        
        NotificationCenter.default.addObserver(self, selector: #selector(appDidBecomeActive),
                                                name: UIApplication.didBecomeActiveNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appDidEnterBackground),
                                                name: UIApplication.didEnterBackgroundNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appWillTerminate),
                                                name: UIApplication.willTerminateNotification, object: nil)
    }
    
    @objc private func appDidBecomeActive() {
        log(level: .info, category: "APP_LIFECYCLE", message: "App became active",
            metadata: ["userId": userId ?? "none", "sessionId": sessionId])
    }
    
    @objc private func appDidEnterBackground() {
        log(level: .info, category: "APP_LIFECYCLE", message: "App entered background",
            metadata: ["userId": userId ?? "none", "sessionId": sessionId])
        flushLogs()
    }
    
    @objc private func appWillTerminate() {
        log(level: .info, category: "APP_LIFECYCLE", message: "App will terminate",
            metadata: ["userId": userId ?? "none", "sessionId": sessionId])
        flushLogs()
    }
    
    // MARK: - Core Logging
    
    func log(level: LogLevel, category: String, message: String, metadata: [String: Any]? = nil) {
        let timestamp = dateFormatter.string(from: Date())
        var logEntry = "[\(level.rawValue)][\(category)] \(timestamp) | \(message)"
        
        if let metadata = metadata {
            let metadataString = metadata.map { "\($0.key)=\($0.value)" }.joined(separator: " | ")
            logEntry += " | \(metadataString)"
        }
        
        if let uid = userId {
            logEntry += " | uid=\(uid)"
        }
        
        NSLog("%@", logEntry)
        
        switch level {
        case .debug:
            print("🔍 \(logEntry)")
        case .info:
            print("ℹ️ \(logEntry)")
        case .warning:
            print("⚠️ \(logEntry)")
        case .error:
            print("❌ \(logEntry)")
        case .critical:
            print("🔴 \(logEntry)")
        }
        
        bufferQueue.async(flags: .barrier) {
            self.logBuffer.append(logEntry)
            if self.logBuffer.count > self.maxBufferSize {
                self.logBuffer.removeFirst(self.logBuffer.count - self.maxBufferSize)
            }
        }
    }
    
    // MARK: - Authentication Flow Tracking
    
    func trackLoginAttempt(email: String, method: String) {
        NSLog("[AUTH][LOGIN_ATTEMPT] Email: %@ | Method: %@ | Session: %@", email, method, sessionId)
        print("🔐 [LOGIN_ATTEMPT] User attempting login - Email: \(email), Method: \(method)")
        
        log(level: .info, category: "AUTH",
            message: "Login attempt initiated",
            metadata: [
                "email": email,
                "method": method,
                "sessionId": sessionId,
                "timestamp": Date().timeIntervalSince1970
            ])
    }
    
    func trackLoginSuccess(userId: String, email: String, accessToken: String, refreshToken: String,
                           tokenExpiry: Date?, userProfile: [String: Any]?) {
        self.userId = userId
        self.userEmail = email
        self.authToken = accessToken
        self.refreshToken = refreshToken
        
        NSLog("[AUTH][LOGIN_SUCCESS] UserID: %@ | Email: %@ | AccessToken: %@ | RefreshToken: %@ | TokenExpiry: %@",
              userId, email, accessToken, refreshToken, tokenExpiry?.description ?? "none")
        
        print("✅ [LOGIN_SUCCESS] User authenticated successfully")
        print("   → User ID: \(userId)")
        print("   → Email: \(email)")
        print("   → Access Token: \(accessToken)")
        print("   → Refresh Token: \(refreshToken)")
        print("   → Token Expiry: \(tokenExpiry?.description ?? "N/A")")
        
        if let profile = userProfile {
            let profileJSON = prettyJSON(profile)
            NSLog("[AUTH][USER_PROFILE] %@", profileJSON)
            print("   → User Profile: \(profileJSON)")
        }
        
        log(level: .info, category: "AUTH",
            message: "Login successful",
            metadata: [
                "userId": userId,
                "email": email,
                "accessToken": accessToken,
                "refreshToken": refreshToken,
                "tokenExpiry": tokenExpiry?.description ?? "none",
                "profile": userProfile ?? [:]
            ])
    }
    
