    func trackTokenRefresh(oldToken: String, newToken: String, newRefreshToken: String?) {
        let previousToken = self.authToken ?? "none"
        self.authToken = newToken
        if let newRefresh = newRefreshToken {
            self.refreshToken = newRefresh
        }
        
        NSLog("[AUTH][TOKEN_REFRESH] OldAccessToken: %@ | NewAccessToken: %@ | NewRefreshToken: %@ | UserID: %@",
              oldToken, newToken, newRefreshToken ?? "unchanged", userId ?? "none")
        
        print("🔄 [TOKEN_REFRESH] Token refreshed")
        print("   → Previous Token: \(previousToken)")
        print("   → New Access Token: \(newToken)")
        print("   → New Refresh Token: \(newRefreshToken ?? "unchanged")")
        print("   → User ID: \(userId ?? "N/A")")
        
        log(level: .info, category: "AUTH",
            message: "Token refreshed",
            metadata: [
                "oldToken": oldToken,
                "newToken": newToken,
                "newRefreshToken": newRefreshToken ?? "unchanged",
                "userId": userId ?? "none"
            ])
    }
    
