    // MARK: - API Call Tracking
    
    func trackAPIRequest(requestId: String, method: String, url: String, headers: [String: String]?,
                         body: Data?, queryParams: [String: String]?) {
        let bodyString = body != nil ? String(data: body!, encoding: .utf8) ?? "binary data (\(body!.count) bytes)" : "none"
        
        NSLog("[API][REQUEST] RequestID: %@ | Method: %@ | URL: %@ | Headers: %@ | Body: %@ | QueryParams: %@ | UserID: %@ | Token: %@",
              requestId, method, url, headers?.description ?? "none", bodyString,
              queryParams?.description ?? "none", userId ?? "none", authToken ?? "none")
        
        print("📡 [API_REQUEST] \(method) \(url)")
        print("   → Request ID: \(requestId)")
        print("   → Headers: \(headers?.description ?? "none")")
        print("   → Body: \(bodyString)")
        print("   → Query Params: \(queryParams?.description ?? "none")")
        print("   → Auth Token: \(authToken ?? "none")")
        print("   → User ID: \(userId ?? "none")")
        
        log(level: .debug, category: "API",
            message: "API request sent",
            metadata: [
                "requestId": requestId,
                "method": method,
                "url": url,
                "headers": headers ?? [:],
                "body": bodyString,
                "queryParams": queryParams ?? [:],
                "authToken": authToken ?? "none"
            ])
    }
    
    func trackAPIResponse(requestId: String, url: String, statusCode: Int, headers: [String: String]?,
                          responseBody: Data?, duration: TimeInterval) {
        let bodyString = responseBody != nil ?
            String(data: responseBody!, encoding: .utf8) ?? "binary data (\(responseBody!.count) bytes)" : "none"
        
        NSLog("[API][RESPONSE] RequestID: %@ | URL: %@ | Status: %d | Duration: %.3fs | ResponseHeaders: %@ | ResponseBody: %@ | UserID: %@",
              requestId, url, statusCode, duration, headers?.description ?? "none", bodyString, userId ?? "none")
        
        let emoji = (200..<300).contains(statusCode) ? "✅" : "❌"
        print("\(emoji) [API_RESPONSE] Status \(statusCode) from \(url)")
        print("   → Request ID: \(requestId)")
        print("   → Duration: \(String(format: "%.3f", duration))s")
        print("   → Response Headers: \(headers?.description ?? "none")")
        print("   → Response Body: \(bodyString)")
        print("   → User ID: \(userId ?? "none")")
        
        let level: LogLevel = (200..<300).contains(statusCode) ? .debug : .error
        log(level: level, category: "API",
            message: "API response received",
            metadata: [
                "requestId": requestId,
                "url": url,
                "statusCode": statusCode,
                "duration": duration,
                "responseHeaders": headers ?? [:],
                "responseBody": bodyString
            ])
    }
    
