    // MARK: - Error Tracking
    
    func trackError(error: Error, context: String, severity: LogLevel = .error, additionalInfo: [String: Any]? = nil) {
        let nsError = error as NSError
        
        NSLog("[ERROR][%@] Context: %@ | Domain: %@ | Code: %d | Description: %@ | UserInfo: %@ | UserID: %@ | Email: %@ | Token: %@ | AdditionalInfo: %@",
              severity.rawValue, context, nsError.domain, nsError.code, nsError.localizedDescription,
              nsError.userInfo.description, userId ?? "none", userEmail ?? "none",
              authToken ?? "none", additionalInfo?.description ?? "none")
        
        print("🚨 [ERROR] \(context)")
        print("   → Error: \(error)")
        print("   → Domain: \(nsError.domain)")
        print("   → Code: \(nsError.code)")
        print("   → Description: \(nsError.localizedDescription)")
        print("   → User Info: \(nsError.userInfo)")
        print("   → User ID: \(userId ?? "N/A")")
        print("   → Email: \(userEmail ?? "N/A")")
        print("   → Auth Token: \(authToken ?? "N/A")")
        if let info = additionalInfo {
            print("   → Additional Info: \(prettyJSON(info))")
        }
        
        log(level: severity, category: "ERROR",
            message: "\(context): \(error.localizedDescription)",
            metadata: [
                "errorDomain": nsError.domain,
                "errorCode": nsError.code,
                "errorDescription": nsError.localizedDescription,
                "errorUserInfo": nsError.userInfo.description,
                "context": context,
                "authToken": authToken ?? "none",
                "additionalInfo": additionalInfo ?? [:]
            ])
    }
    
    func trackCrashPrecursor(reason: String, stackTrace: [String]?, state: [String: Any]?) {
        NSLog("[CRITICAL][CRASH_PRECURSOR] Reason: %@ | UserID: %@ | Email: %@ | Token: %@ | State: %@ | Stack: %@",
              reason, userId ?? "none", userEmail ?? "none", authToken ?? "none",
              state?.description ?? "none", stackTrace?.joined(separator: "\n") ?? "none")
        
        print("💥 [CRASH_PRECURSOR] Potential crash detected!")
        print("   → Reason: \(reason)")
        print("   → User ID: \(userId ?? "N/A")")
        print("   → Email: \(userEmail ?? "N/A")")
        print("   → Auth Token: \(authToken ?? "N/A")")
        print("   → Refresh Token: \(refreshToken ?? "N/A")")
        if let state = state {
            print("   → App State: \(prettyJSON(state))")
        }
        if let stack = stackTrace {
            print("   → Stack Trace:")
            stack.forEach { print("      \($0)") }
        }
        
        log(level: .critical, category: "CRASH",
            message: reason,
            metadata: [
                "stackTrace": stackTrace ?? [],
                "appState": state ?? [:],
                "authToken": authToken ?? "none",
                "refreshToken": refreshToken ?? "none"
            ])
        
        flushLogs()
    }
    
    func trackNetworkError(url: String, method: String, statusCode: Int?, error: Error?,
                           requestHeaders: [String: String]?, requestBody: Data?,
                           responseBody: Data?) {
        let reqBodyStr = requestBody.flatMap { String(data: $0, encoding: .utf8) } ?? "none"
        let resBodyStr = responseBody.flatMap { String(data: $0, encoding: .utf8) } ?? "none"
        
        NSLog("[ERROR][NETWORK] URL: %@ | Method: %@ | Status: %d | Error: %@ | ReqHeaders: %@ | ReqBody: %@ | ResBody: %@ | UserID: %@ | Token: %@",
              url, method, statusCode ?? -1, error?.localizedDescription ?? "none",
              requestHeaders?.description ?? "none", reqBodyStr, resBodyStr,
              userId ?? "none", authToken ?? "none")
        
        print("🌐 [NETWORK_ERROR] \(method) \(url)")
        print("   → Status Code: \(statusCode ?? -1)")
        print("   → Error: \(error?.localizedDescription ?? "N/A")")
        print("   → Request Headers: \(requestHeaders?.description ?? "none")")
        print("   → Request Body: \(reqBodyStr)")
        print("   → Response Body: \(resBodyStr)")
        print("   → User ID: \(userId ?? "N/A")")
        print("   → Auth Token: \(authToken ?? "N/A")")
        
        log(level: .error, category: "NETWORK_ERROR",
            message: "Network request failed: \(method) \(url)",
            metadata: [
                "url": url,
                "method": method,
                "statusCode": statusCode ?? -1,
                "error": error?.localizedDescription ?? "none",
                "requestHeaders": requestHeaders ?? [:],
                "requestBody": reqBodyStr,
                "responseBody": resBodyStr,
                "authToken": authToken ?? "none"
            ])
    }
    
