    // MARK: - Performance Tracking
    
    func trackPerformanceMetric(name: String, duration: TimeInterval, metadata: [String: Any]? = nil) {
        NSLog("[PERFORMANCE][%@] Duration: %.3fs | UserID: %@ | Metadata: %@",
              name, duration, userId ?? "none", metadata?.description ?? "none")
        
        let emoji = duration > 3.0 ? "🐌" : (duration > 1.0 ? "⏱️" : "⚡")
        print("\(emoji) [PERFORMANCE] \(name): \(String(format: "%.3f", duration))s")
        if let meta = metadata {
            print("   → Details: \(meta)")
        }
        
        let level: LogLevel = duration > 5.0 ? .warning : .debug
        log(level: level, category: "PERFORMANCE",
            message: "\(name) completed in \(String(format: "%.3f", duration))s",
            metadata: [
                "metricName": name,
                "duration": duration,
                "additionalMetadata": metadata ?? [:]
            ])
    }
    
    func startTimer(name: String) -> CFAbsoluteTime {
        let startTime = CFAbsoluteTimeGetCurrent()
        NSLog("[PERFORMANCE][TIMER_START] %@ | Timestamp: %f", name, startTime)
        print("⏱️ [TIMER_START] \(name)")
        return startTime
    }
    
    func endTimer(name: String, startTime: CFAbsoluteTime, metadata: [String: Any]? = nil) {
        let duration = CFAbsoluteTimeGetCurrent() - startTime
        trackPerformanceMetric(name: name, duration: duration, metadata: metadata)
    }
    
