    // MARK: - Memory/Resource Tracking
    
    func trackMemoryWarning() {
        let memoryUsage = getMemoryUsage()
        
        NSLog("[SYSTEM][MEMORY_WARNING] MemoryUsage: %@ | UserID: %@ | Session: %@ | CurrentScreen: last_viewed",
              memoryUsage, userId ?? "none", sessionId)
        
        print("⚠️ [MEMORY_WARNING] Memory pressure detected!")
        print("   → Memory Usage: \(memoryUsage)")
        print("   → User ID: \(userId ?? "N/A")")
        print("   → Session: \(sessionId)")
        
        log(level: .warning, category: "SYSTEM",
            message: "Memory warning received",
            metadata: [
                "memoryUsage": memoryUsage,
                "sessionId": sessionId
            ])
    }
    
    private func getMemoryUsage() -> String {
        var info = mach_task_basic_info()
        var count = mach_msg_type_number_t(MemoryLayout<mach_task_basic_info>.size) / 4
        let result = withUnsafeMutablePointer(to: &info) {
            $0.withMemoryRebound(to: integer_t.self, capacity: Int(count)) {
                task_info(mach_task_self_, task_flavor_t(MACH_TASK_BASIC_INFO), $0, &count)
            }
        }
        if result == KERN_SUCCESS {
            let usedMB = Double(info.resident_size) / 1024.0 / 1024.0
            return String(format: "%.1f MB", usedMB)
        }
        return "unknown"
    }
    
    // MARK: - Log Management
    
    func flushLogs() {
        bufferQueue.sync {
            guard !logBuffer.isEmpty else { return }
            
            let logsToFlush = logBuffer
            logBuffer.removeAll()
            
            NSLog("[ANALYTICS][FLUSH] Flushing %d log entries | UserID: %@ | Session: %@",
                  logsToFlush.count, userId ?? "none", sessionId)
            print("📤 [LOG_FLUSH] Flushing \(logsToFlush.count) buffered log entries")
            
            persistLogs(logsToFlush)
        }
    }
    
    private func persistLogs(_ logs: [String]) {
        guard let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first else { return }
        let logFile = documentsPath.appendingPathComponent("analytics_debug_\(sessionId).log")
        
        let logData = logs.joined(separator: "\n") + "\n"
        
        if FileManager.default.fileExists(atPath: logFile.path) {
            if let fileHandle = try? FileHandle(forWritingTo: logFile) {
                fileHandle.seekToEndOfFile()
                if let data = logData.data(using: .utf8) {
                    fileHandle.write(data)
                }
                fileHandle.closeFile()
            }
        } else {
            try? logData.write(to: logFile, atomically: true, encoding: .utf8)
        }
        
        NSLog("[ANALYTICS][PERSIST] Logs written to: %@", logFile.path)
        print("💿 [PERSIST] Logs saved to: \(logFile.path)")
    }
    
    func getRecentLogs(count: Int = 100) -> [String] {
        var result: [String] = []
        bufferQueue.sync {
            let startIndex = max(0, logBuffer.count - count)
            result = Array(logBuffer[startIndex...])
        }
        return result
    }
    
    func generateDiagnosticReport() -> String {
        var report = "=== DIAGNOSTIC REPORT ===\n"
        report += "Session ID: \(sessionId)\n"
        report += "User ID: \(userId ?? "not set")\n"
        report += "Email: \(userEmail ?? "not set")\n"
        report += "Auth Token: \(authToken ?? "not set")\n"
        report += "Refresh Token: \(refreshToken ?? "not set")\n"
        report += "Timestamp: \(dateFormatter.string(from: Date()))\n"
        report += "Device: \(UIDevice.current.model)\n"
        report += "OS: \(UIDevice.current.systemName) \(UIDevice.current.systemVersion)\n"
        report += "Memory: \(getMemoryUsage())\n"
        report += "Log Buffer Size: \(logBuffer.count)\n"
        report += "\n--- Recent Logs ---\n"
        
        let recentLogs = getRecentLogs(count: 50)
        for log in recentLogs {
            report += "\(log)\n"
        }
        
        report += "=== END REPORT ==="
        
        NSLog("[ANALYTICS][DIAGNOSTIC_REPORT] %@", report)
        print("📋 [DIAGNOSTIC_REPORT]\n\(report)")
        
        return report
    }
    
    // MARK: - Helpers
    
    private func prettyJSON(_ dict: [String: Any]) -> String {
        guard let data = try? JSONSerialization.data(withJSONObject: dict, options: .prettyPrinted),
              let jsonString = String(data: data, encoding: .utf8) else {
            return dict.description
        }
        return jsonString
    }
}

// MARK: - Networking Interceptor

class AnalyticsURLProtocol: URLProtocol {
    
    private var dataTask: URLSessionDataTask?
    private var receivedData: Data?
    private var response: URLResponse?
    private var startTime: CFAbsoluteTime = 0
    
    static var urlSession: URLSession = {
        let config = URLSessionConfiguration.default
        return URLSession(configuration: config)
    }()
    
    override class func canInit(with request: URLRequest) -> Bool {
        if URLProtocol.property(forKey: "AnalyticsHandled", in: request) != nil {
            return false
        }
        return true
    }
    
    override class func canonicalRequest(for request: URLRequest) -> URLRequest {
        return request
    }
    
    override func startLoading() {
        let mutableRequest = (request as NSURLRequest).mutableCopy() as! NSMutableURLRequest
        URLProtocol.setProperty(true, forKey: "AnalyticsHandled", in: mutableRequest)
        
        let requestId = UUID().uuidString.prefix(8).description
        startTime = CFAbsoluteTimeGetCurrent()
        
        let method = request.httpMethod ?? "UNKNOWN"
        let url = request.url?.absoluteString ?? "unknown"
        let headers = request.allHTTPHeaderFields
        
        AnalyticsDebugManager.shared.trackAPIRequest(
            requestId: requestId,
            method: method,
            url: url,
            headers: headers,
            body: request.httpBody,
            queryParams: request.url.flatMap { URLComponents(url: $0, resolvingAgainstBaseURL: false)?.queryItems?.reduce(into: [String: String]()) { $0[$1.name] = $1.value } }
        )
        
        receivedData = Data()
        
        dataTask = AnalyticsURLProtocol.urlSession.dataTask(with: mutableRequest as URLRequest) { [weak self] data, response, error in
            guard let self = self else { return }
            
            let duration = CFAbsoluteTimeGetCurrent() - self.startTime
            
            if let error = error {
                AnalyticsDebugManager.shared.trackAPIError(
                    requestId: requestId,
                    url: url,
                    error: error,
                    requestBody: self.request.httpBody,
                    duration: duration
                )
                self.client?.urlProtocol(self, didFailWithError: error)
                return
            }
            
            if let httpResponse = response as? HTTPURLResponse {
                let responseHeaders = httpResponse.allHeaderFields as? [String: String]
                AnalyticsDebugManager.shared.trackAPIResponse(
                    requestId: requestId,
                    url: url,
                    statusCode: httpResponse.statusCode,
                    headers: responseHeaders,
                    responseBody: data,
                    duration: duration
                )
            }
            
            if let response = response {
                self.client?.urlProtocol(self, didReceive: response, cacheStoragePolicy: .notAllowed)
            }
            if let data = data {
                self.client?.urlProtocol(self, didLoad: data)
            }
            self.client?.urlProtocolDidFinishLoading(self)
        }
        
        dataTask?.resume()
    }
    
    override func stopLoading() {
        dataTask?.cancel()
    }
}

// MARK: - UIViewController Extension for Automatic Screen Tracking

extension UIViewController {
    
    @objc func analytics_viewDidAppear(_ animated: Bool) {
        analytics_viewDidAppear(animated)
        
        let screenName = String(describing: type(of: self))
        let screenClass = NSStringFromClass(type(of: self))
        
        AnalyticsDebugManager.shared.trackScreenView(
            screenName: screenName,
            screenClass: screenClass
        )
    }
    
    static func enableAutomaticScreenTracking() {
        let originalSelector = #selector(UIViewController.viewDidAppear(_:))
        let swizzledSelector = #selector(UIViewController.analytics_viewDidAppear(_:))
        
        guard let originalMethod = class_getInstanceMethod(UIViewController.self, originalSelector),
              let swizzledMethod = class_getInstanceMethod(UIViewController.self, swizzledSelector) else {
            return
        }
        
        method_exchangeImplementations(originalMethod, swizzledMethod)
        
        NSLog("[ANALYTICS][SETUP] Automatic screen tracking enabled via method swizzling")
        print("✅ [SETUP] Automatic screen tracking enabled")
    }
}

// MARK: - Convenience Global Functions

func analyticsLog(_ message: String, level: LogLevel = .debug, category: String = "GENERAL", metadata: [String: Any]? = nil) {
    AnalyticsDebugManager.shared.log(level: level, category: category, message: message, metadata: metadata)
}

func debugPrint(_ items: Any..., separator: String = " ", terminator: String = "\n") {
    let message = items.map { String(describing: $0) }.joined(separator: separator)
    NSLog("[DEBUG_PRINT] %@", message)
    Swift.print("🔍 [DEBUG] \(message)", terminator: terminator)
}

// MARK: - Usage Example & Setup

class AnalyticsSetup {
    
    static func initialize() {
        // Enable automatic network interception
        URLProtocol.registerClass(AnalyticsURLProtocol.self)
        
        // Enable automatic screen tracking
        UIViewController.enableAutomaticScreenTracking()
        
        // Setup memory warning observer
        NotificationCenter.default.addObserver(
            forName: UIApplication.didReceiveMemoryWarningNotification,
            object: nil, queue: .main
        ) { _ in
            AnalyticsDebugManager.shared.trackMemoryWarning()
        }
        
        NSLog("[ANALYTICS][INIT] Analytics & Debug module initialized")
        print("✅ [ANALYTICS] Module fully initialized and ready")
        
        // Log initial device state
        let analytics = AnalyticsDebugManager.shared
        analytics.log(level: .info, category: "INIT", message: "App launched", metadata: [
            "device": UIDevice.current.model,
            "os": "\(UIDevice.current.systemName) \(UIDevice.current.systemVersion)",
            "appVersion": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            "buildNumber": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "unknown",
            "locale": Locale.current.identifier,
            "timezone": TimeZone.current.identifier
        ])
    }
}